from __future__ import annotations

from dataclasses import dataclass
import json
import math
import os
from pathlib import Path
from collections.abc import Iterable
from typing import Protocol

from vllm.v1.request import Request


@dataclass(frozen=True)
class RequestFeatures:
    """Lightweight scheduling features extracted from a vLLM request."""

    request_id: str
    arrival_time: float
    priority: int
    prompt_tokens: int
    output_tokens: int
    max_tokens: int
    current_tokens: int
    estimated_total_tokens: int

    @classmethod
    def from_request(cls, request: Request) -> "RequestFeatures":
        prompt_tokens = int(request.num_prompt_tokens)
        output_tokens = int(request.num_output_tokens)
        max_tokens = int(request.max_tokens)
        return cls(
            request_id=request.request_id,
            arrival_time=float(request.arrival_time),
            priority=int(request.priority),
            prompt_tokens=prompt_tokens,
            output_tokens=output_tokens,
            max_tokens=max_tokens,
            current_tokens=int(request.num_tokens),
            estimated_total_tokens=prompt_tokens + max_tokens,
        )


class SchedulerPolicyPlugin(Protocol):
    """Small policy interface used by request queues.

    Lower sort keys are scheduled earlier.
    """

    name: str

    def sort_key(self, request: Request) -> tuple[object, ...]:
        ...


class FCFSPolicy:
    name = "fcfs"

    def sort_key(self, request: Request) -> tuple[object, ...]:
        features = RequestFeatures.from_request(request)
        return (features.arrival_time, features.request_id)


class PriorityPolicy:
    name = "priority"

    def sort_key(self, request: Request) -> tuple[object, ...]:
        features = RequestFeatures.from_request(request)
        return (features.priority, features.arrival_time, features.request_id)


class LengthOnlyPolicy:
    name = "length_only"

    def sort_key(self, request: Request) -> tuple[object, ...]:
        features = RequestFeatures.from_request(request)
        return (
            features.estimated_total_tokens,
            features.prompt_tokens,
            features.arrival_time,
            features.request_id,
        )


class LTRPolicy:
    """Learning-to-rank scheduler policy with an external score source.

    The paper's ranking scheduler uses a predictor to score requests and then
    schedules by `(priority, score)`. This implementation keeps the scheduler
    path independent from any specific predictor: a sidecar process or offline
    predictor can write scores to `VLLM_LTR_SCORE_FILE`, and vLLM uses those
    scores when requests enter the waiting queue.

    Score convention: lower scores are scheduled earlier. Missing scores fall
    back to the same proxy used by `LengthOnlyPolicy`.
    """

    name = "ltr"

    def __init__(self) -> None:
        self._scores = self._load_scores()
        self._direction = os.environ.get("VLLM_LTR_SCORE_DIRECTION", "ascending")

    @staticmethod
    def _canonical_request_ids(request_id: str) -> tuple[str, ...]:
        candidates = [request_id]
        for prefix in ("cmpl-", "chatcmpl-"):
            if request_id.startswith(prefix):
                candidates.append(request_id[len(prefix) :])
        return tuple(dict.fromkeys(candidates))

    @staticmethod
    def _coerce_score(value: object) -> float:
        if isinstance(value, dict):
            for key in ("score", "ltr_score", "predicted_score", "rank", "predicted_rank"):
                if key in value:
                    return float(value[key])
        return float(value)

    @classmethod
    def _load_score_rows(cls, path: Path) -> dict[str, float]:
        if path.suffix == ".jsonl":
            rows = []
            with path.open("r", encoding="utf-8") as f:
                for line in f:
                    line = line.strip()
                    if line:
                        rows.append(json.loads(line))
        else:
            text = path.read_text(encoding="utf-8")
            try:
                rows = json.loads(text)
            except json.JSONDecodeError:
                rows = [json.loads(line) for line in text.splitlines() if line.strip()]

        scores: dict[str, float] = {}
        if isinstance(rows, dict):
            for request_id, score in rows.items():
                scores[str(request_id)] = cls._coerce_score(score)
            return scores

        if not isinstance(rows, list):
            raise ValueError(f"LTR score file must contain a JSON object or list: {path}")

        for row in rows:
            if not isinstance(row, dict):
                raise ValueError(f"LTR score row must be an object: {row!r}")
            request_id = row.get("request_id", row.get("id"))
            if request_id is None:
                raise ValueError(f"LTR score row is missing request_id/id: {row!r}")
            scores[str(request_id)] = cls._coerce_score(row)
        return scores

    @classmethod
    def _load_scores(cls) -> dict[str, float]:
        score_file = os.environ.get("VLLM_LTR_SCORE_FILE")
        if not score_file:
            return {}
        path = Path(score_file)
        if not path.exists():
            raise FileNotFoundError(f"VLLM_LTR_SCORE_FILE does not exist: {path}")
        return cls._load_score_rows(path)

    def _score(self, features: RequestFeatures) -> float:
        for request_id in self._canonical_request_ids(features.request_id):
            if request_id in self._scores:
                score = self._scores[request_id]
                if self._direction == "descending":
                    return -score
                return score
        return float(features.estimated_total_tokens)

    def sort_key(self, request: Request) -> tuple[object, ...]:
        features = RequestFeatures.from_request(request)
        return (
            features.priority,
            self._score(features),
            features.estimated_total_tokens,
            features.prompt_tokens,
            features.arrival_time,
            features.request_id,
        )


class MoEAffinityPolicy:
    """MoE-locality-aware scheduler policy.

    This policy keeps a length/LTR-like static key for heap insertion, then
    exposes a dynamic key that reranks a small waiting-window by similarity to
    the current running batch. Expert signatures are supplied out-of-band so the
    scheduler can validate the locality signal without changing the model
    execution path.
    """

    name = "moe_affinity"

    def __init__(self) -> None:
        self._signatures = self._load_signatures()
        self._base_scores = self._load_base_scores()
        self._score_direction = os.environ.get(
            "VLLM_MOE_AFFINITY_SCORE_DIRECTION",
            os.environ.get("VLLM_LTR_SCORE_DIRECTION", "ascending"),
        )
        self._topk = int(os.environ.get("VLLM_MOE_AFFINITY_TOPK", "8"))
        self._bucket_size = float(
            os.environ.get("VLLM_MOE_AFFINITY_BUCKET_SIZE", "32")
        )
        self._weight = float(os.environ.get("VLLM_MOE_AFFINITY_WEIGHT", "1.0"))

    @staticmethod
    def _canonical_request_ids(request_id: str) -> tuple[str, ...]:
        return LTRPolicy._canonical_request_ids(request_id)

    @staticmethod
    def _feature_key(layer: object, expert: object) -> str:
        return f"{int(layer)}:{int(expert)}"

    @classmethod
    def _coerce_signature(cls, row: object) -> dict[str, float]:
        if not isinstance(row, dict):
            raise ValueError(f"MoE affinity signature row must be an object: {row!r}")

        raw = row.get("signature", row.get("experts", row.get("expert_signature")))
        if raw is None:
            return {}

        signature: dict[str, float] = {}
        if isinstance(raw, dict):
            for key, value in raw.items():
                signature[str(key)] = float(value)
            return signature

        if not isinstance(raw, list):
            raise ValueError(f"Unsupported MoE signature format: {raw!r}")

        for item in raw:
            if isinstance(item, dict):
                layer = item.get("layer", item.get("layer_id"))
                expert = item.get("expert", item.get("expert_id"))
                weight = item.get("weight", item.get("count", 1.0))
            elif isinstance(item, (list, tuple)) and len(item) >= 2:
                layer = item[0]
                expert = item[1]
                weight = item[2] if len(item) >= 3 else 1.0
            else:
                raise ValueError(f"Unsupported MoE signature entry: {item!r}")

            if layer is None or expert is None:
                raise ValueError(f"MoE signature entry missing layer/expert: {item!r}")
            key = cls._feature_key(layer, expert)
            signature[key] = signature.get(key, 0.0) + float(weight)
        return signature

    @staticmethod
    def _load_json_rows(path: Path) -> object:
        if path.suffix == ".jsonl":
            rows = []
            with path.open("r", encoding="utf-8") as f:
                for line in f:
                    line = line.strip()
                    if line:
                        rows.append(json.loads(line))
            return rows

        text = path.read_text(encoding="utf-8")
        try:
            return json.loads(text)
        except json.JSONDecodeError:
            return [json.loads(line) for line in text.splitlines() if line.strip()]

    @classmethod
    def _load_signatures(cls) -> dict[str, dict[str, float]]:
        signature_file = os.environ.get("VLLM_MOE_AFFINITY_SIGNATURE_FILE")
        if not signature_file:
            return {}
        path = Path(signature_file)
        if not path.exists():
            raise FileNotFoundError(
                f"VLLM_MOE_AFFINITY_SIGNATURE_FILE does not exist: {path}"
            )

        rows = cls._load_json_rows(path)
        signatures: dict[str, dict[str, float]] = {}
        if isinstance(rows, dict):
            for request_id, signature in rows.items():
                signatures[str(request_id)] = cls._coerce_signature(
                    {"signature": signature}
                )
            return signatures

        if not isinstance(rows, list):
            raise ValueError(
                f"MoE affinity signature file must contain an object or list: {path}"
            )

        for row in rows:
            if not isinstance(row, dict):
                raise ValueError(f"MoE affinity signature row must be an object: {row!r}")
            request_id = row.get("request_id", row.get("id"))
            if request_id is None:
                raise ValueError(
                    f"MoE affinity signature row is missing request_id/id: {row!r}"
                )
            signatures[str(request_id)] = cls._coerce_signature(row)
        return signatures

    @classmethod
    def _load_base_scores(cls) -> dict[str, float]:
        score_file = os.environ.get("VLLM_MOE_AFFINITY_SCORE_FILE")
        if not score_file:
            score_file = os.environ.get("VLLM_LTR_SCORE_FILE")
        if not score_file:
            return {}

        path = Path(score_file)
        if not path.exists():
            raise FileNotFoundError(f"MoE affinity score file does not exist: {path}")
        return LTRPolicy._load_score_rows(path)

    @property
    def rerank_topk(self) -> int:
        return max(1, self._topk)

    def _signature_for_request_id(self, request_id: str) -> dict[str, float]:
        for candidate in self._canonical_request_ids(request_id):
            signature = self._signatures.get(candidate)
            if signature is not None:
                return signature
        return {}

    def signature(self, request: Request) -> dict[str, float]:
        return self._signature_for_request_id(request.request_id)

    def _base_score(self, features: RequestFeatures) -> float:
        for request_id in self._canonical_request_ids(features.request_id):
            if request_id in self._base_scores:
                score = self._base_scores[request_id]
                if self._score_direction == "descending":
                    return -score
                return score
        return float(features.estimated_total_tokens)

    @staticmethod
    def _aggregate_signature(requests: Iterable[Request], policy: "MoEAffinityPolicy") -> dict[str, float]:
        aggregate: dict[str, float] = {}
        for request in requests:
            for key, value in policy.signature(request).items():
                aggregate[key] = aggregate.get(key, 0.0) + value
        return aggregate

    @staticmethod
    def _cosine_similarity(left: dict[str, float], right: dict[str, float]) -> float:
        if not left or not right:
            return 0.0
        if len(left) > len(right):
            left, right = right, left
        dot = sum(value * right.get(key, 0.0) for key, value in left.items())
        if dot <= 0.0:
            return 0.0
        left_norm = math.sqrt(sum(value * value for value in left.values()))
        right_norm = math.sqrt(sum(value * value for value in right.values()))
        if left_norm == 0.0 or right_norm == 0.0:
            return 0.0
        return dot / (left_norm * right_norm)

    def affinity_to_running(self, request: Request, running: Iterable[Request]) -> float:
        running_signature = self._aggregate_signature(running, self)
        return self._cosine_similarity(self.signature(request), running_signature)

    def sort_key(self, request: Request) -> tuple[object, ...]:
        features = RequestFeatures.from_request(request)
        base_score = self._base_score(features)
        return (
            features.priority,
            base_score,
            features.estimated_total_tokens,
            features.prompt_tokens,
            features.arrival_time,
            features.request_id,
        )

    def dynamic_sort_key(
        self, request: Request, running: Iterable[Request]
    ) -> tuple[object, ...]:
        features = RequestFeatures.from_request(request)
        base_score = self._base_score(features)
        base_bucket = (
            math.floor(base_score / self._bucket_size)
            if self._bucket_size > 0
            else base_score
        )
        length_bucket = (
            math.floor(features.estimated_total_tokens / self._bucket_size)
            if self._bucket_size > 0
            else features.estimated_total_tokens
        )
        affinity = self.affinity_to_running(request, running)
        return (
            features.priority,
            base_bucket,
            length_bucket,
            -self._weight * affinity,
            base_score,
            features.estimated_total_tokens,
            features.prompt_tokens,
            features.arrival_time,
            features.request_id,
        )


_POLICY_PLUGINS: dict[str, SchedulerPolicyPlugin] = {
    FCFSPolicy.name: FCFSPolicy(),
    PriorityPolicy.name: PriorityPolicy(),
    LengthOnlyPolicy.name: LengthOnlyPolicy(),
    LTRPolicy.name: LTRPolicy(),
    MoEAffinityPolicy.name: MoEAffinityPolicy(),
}


def get_scheduler_policy_plugin(name: str) -> SchedulerPolicyPlugin:
    try:
        return _POLICY_PLUGINS[name]
    except KeyError as exc:
        raise ValueError(f"Unknown scheduling policy: {name}") from exc
